import React, { useState, useEffect } from 'react';
import { Box, Heading, Button, Flex, Table, Tbody, Td, Th, Thead, Tr, useToast, Spinner } from '@chakra-ui/react';
import axios from 'axios';
import moment from 'moment';

const AdminDashboard = () => {
  const [view, setView] = useState('realTime'); // 'realTime' or 'browseAndDownload'
  const [currentTasks, setCurrentTasks] = useState([]);
  const [loading, setLoading] = useState(true); // Initial loading state
  const toast = useToast();

  useEffect(() => {
    let intervalId;

    if (view === 'realTime') {
      // Fetch initial tasks
      fetchCurrentTasks();

      // Set interval to update the task timers
      intervalId = setInterval(() => {
        updateTaskTimers();
      }, 1000); // Update every second
    }

    return () => {
      if (intervalId) clearInterval(intervalId);
    };
  }, [view]);

  // Fetch Current Tasks for Real-Time Monitoring
  const fetchCurrentTasks = async () => {
    setLoading(true);
    try {
      const response = await axios.get('http://localhost:5000/api/tasks/current-tasks', {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('authToken')}`,
        },
      });
      setCurrentTasks(response.data);
    } catch (error) {
      console.error('Error fetching current tasks:', error);
      toast({
        title: 'Error',
        description: 'Failed to fetch tasks. Please try again.',
        status: 'error',
        duration: 3000,
        isClosable: true,
      });
    } finally {
      setLoading(false); // Stop loading after fetching data
    }
  };

  // Update Task Timers without re-fetching from server
  const updateTaskTimers = () => {
    setCurrentTasks((prevTasks) =>
      prevTasks.map((taskEntry) => {
        if (taskEntry.activeTask && !taskEntry.activeTask.completed) {
          const timeSpentSeconds = Math.floor((Date.now() - new Date(taskEntry.activeTask.createdAt)) / 1000);
          const duration = moment.duration(timeSpentSeconds, 'seconds');
          const formattedTime = `${duration.hours()}h ${duration.minutes()}m ${duration.seconds()}s`;

          return {
            ...taskEntry,
            activeTask: {
              ...taskEntry.activeTask,
              formattedTime,
            },
          };
        }
        return taskEntry;
      })
    );
  };

  return (
    <Box maxW="80%" mx="auto" mt={10} p={5} borderWidth={1} borderRadius="lg">
      <Heading as="h3" size="lg" mb={6} textAlign="center">
        Admin Dashboard
      </Heading>

      {/* Panel for Selecting View */}
      <Flex justifyContent="center" mb={6}>
        <Button colorScheme="teal" mr={4} onClick={() => setView('realTime')}>
          Real-Time Data
        </Button>
      </Flex>

      {/* Real-Time Data View */}
      {view === 'realTime' && (
        <Box>
          <Heading as="h4" size="md" mb={4}>
            Current Status of Team Members
          </Heading>
          {loading ? (
            <Spinner size="lg" />
          ) : (
            <Table variant="striped" colorScheme="teal">
              <Thead>
                <Tr>
                  <Th>Team Member</Th>
                  <Th>Status</Th>
                  <Th>Task ID</Th>
                  <Th>Queue</Th>
                  <Th>Time Spent (so far)</Th>
                </Tr>
              </Thead>
              <Tbody>
                {currentTasks.length > 0 ? (
                  currentTasks.map(({ user, activeTask }) => (
                    <Tr key={user.email}>
                      <Td>{`${user.firstName} ${user.lastName}`}</Td>
                      <Td>{activeTask && !activeTask.completed ? 'Active' : 'Idle'}</Td>
                      <Td>{activeTask && !activeTask.completed ? activeTask.taskId : '-'}</Td>
                      <Td>{activeTask && !activeTask.completed ? activeTask.queue : '-'}</Td>
                      <Td>
                        {activeTask && !activeTask.completed
                          ? activeTask.formattedTime
                          : '-'}
                      </Td>
                    </Tr>
                  ))
                ) : (
                  <Tr>
                    <Td colSpan="5" textAlign="center">
                      No tasks found.
                    </Td>
                  </Tr>
                )}
              </Tbody>
            </Table>
          )}
        </Box>
      )}
    </Box>
  );
};

export default AdminDashboard;
